import React, { useEffect, useState, useCallback } from "react";
import axios from "axios";
import { useParams, useNavigate } from "react-router-dom";
import { FaArrowLeft, FaPlus, FaBoxOpen } from "react-icons/fa";

export default function ProductosPorCategoria() {
  const { categoria_id } = useParams();
  const navigate = useNavigate();

  const [productos, setProductos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);

  const [nuevoProducto, setNuevoProducto] = useState({
    nombre: "",
    descripcion: "",
    precio: "",
    stock: "",
    imagen: null,
  });

  // 📄 PAGINACIÓN
  const [paginaActual, setPaginaActual] = useState(1);
  const productosPorPagina = 8;

  const obtenerProductos = useCallback(async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/productos/categoria/${categoria_id}`
      );

      // Mapeo compatible con MongoDB Atlas (_id)
      setProductos(
        res.data.map((p) => ({
          id: p._id || p.id,
          nombre: p.nombre,
          descripcion: p.descripcion,
          precio: p.precio,
          stock: p.stock,
          imagen: p.imagen,
        }))
      );
    } catch (error) {
      console.error("❌ Error al obtener productos:", error);
    } finally {
      setLoading(false);
    }
  }, [categoria_id]);

  useEffect(() => {
    obtenerProductos();
  }, [obtenerProductos]);

  // 📄 LÓGICA DE PAGINACIÓN
  const totalPaginas = Math.ceil(productos.length / productosPorPagina);
  const inicio = (paginaActual - 1) * productosPorPagina;
  const productosPaginados = productos.slice(inicio, inicio + productosPorPagina);

  const handleChange = (e) => {
    setNuevoProducto({
      ...nuevoProducto,
      [e.target.name]: e.target.value,
    });
  };

  const handleFileChange = (e) => {
    setNuevoProducto({
      ...nuevoProducto,
      imagen: e.target.files[0],
    });
  };

  const guardarProducto = async (e) => {
    e.preventDefault();
    try {
      const formData = new FormData();
      formData.append("nombre", nuevoProducto.nombre);
      formData.append("descripcion", nuevoProducto.descripcion);
      formData.append("precio", nuevoProducto.precio);
      formData.append("stock", nuevoProducto.stock);
      formData.append("categoria_id", categoria_id);

      if (nuevoProducto.imagen) {
        formData.append("imagen", nuevoProducto.imagen);
      }

      await axios.post("http://localhost:5000/api/productos", formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });

      setShowModal(false);
      setNuevoProducto({ nombre: "", descripcion: "", precio: "", stock: "", imagen: null });
      obtenerProductos(); 
    } catch (error) {
      console.error("❌ Error al crear producto:", error);
      alert("Error al guardar el producto");
    }
  };

  if (loading) return <div className="text-center mt-5"><div className="spinner-border text-primary"></div><p>Cargando productos...</p></div>;

  return (
    <div className="container-fluid p-4">
      {/* Cabecera */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <button className="btn btn-outline-secondary shadow-sm" onClick={() => navigate(-1)}>
          <FaArrowLeft className="me-2" /> Volver
        </button>
        <h4 className="fw-bold mb-0 text-dark">
          <FaBoxOpen className="me-2 text-primary" /> Productos de la Categoría
        </h4>
        <button className="btn btn-success shadow-sm" onClick={() => setShowModal(true)}>
          <FaPlus className="me-2" /> Agregar Producto
        </button>
      </div>

      {/* Grid de Productos */}
      <div className="row g-4">
        {productosPaginados.length === 0 ? (
          <div className="col-12 text-center py-5">
            <p className="text-muted">No hay productos en esta categoría todavía.</p>
          </div>
        ) : (
          productosPaginados.map((p) => (
            <div key={p.id} className="col-xl-3 col-lg-4 col-md-6">
              <div className="card h-100 border-0 shadow-sm hover-shadow transition">
                <div style={{ height: "180px", overflow: "hidden" }} className="bg-light">
                  {p.imagen ? (
                    <img
                      src={`http://localhost:5000/uploads/${p.imagen}`}
                      alt={p.nombre}
                      className="card-img-top w-100 h-100"
                      style={{ objectFit: "cover" }}
                    />
                  ) : (
                    <div className="h-100 d-flex align-items-center justify-content-center text-muted">
                      Sin imagen
                    </div>
                  )}
                </div>
                <div className="card-body">
                  <h6 className="fw-bold text-dark text-truncate">{p.nombre}</h6>
                  <p className="small text-muted text-truncate mb-2">{p.descripcion}</p>
                  <div className="d-flex justify-content-between align-items-center">
                    <span className="badge bg-success-subtle text-success fs-6">${p.precio}</span>
                    <span className="small fw-bold">Stock: {p.stock}</span>
                  </div>
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {/* Paginación */}
      {totalPaginas > 1 && (
        <nav className="mt-5">
          <ul className="pagination justify-content-center shadow-sm">
            <li className={`page-item ${paginaActual === 1 && "disabled"}`}>
              <button className="page-link" onClick={() => setPaginaActual(paginaActual - 1)}>Anterior</button>
            </li>
            {[...Array(totalPaginas)].map((_, i) => (
              <li key={i} className={`page-item ${paginaActual === i + 1 ? "active" : ""}`}>
                <button className="page-link" onClick={() => setPaginaActual(i + 1)}>{i + 1}</button>
              </li>
            ))}
            <li className={`page-item ${paginaActual === totalPaginas && "disabled"}`}>
              <button className="page-link" onClick={() => setPaginaActual(paginaActual + 1)}>Siguiente</button>
            </li>
          </ul>
        </nav>
      )}

      {/* Modal - FUERA DEL MAP */}
      {showModal && (
        <div className="modal fade show" style={{ display: "block", background: "rgba(0,0,0,.7)" }}>
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content border-0 shadow-lg">
              <div className="modal-header bg-primary text-white">
                <h5 className="modal-title fw-bold">Nuevo Producto</h5>
                <button type="button" className="btn-close btn-close-white" onClick={() => setShowModal(false)}></button>
              </div>
              <form onSubmit={guardarProducto}>
                <div className="modal-body p-4">
                  <div className="row g-3">
                    <div className="col-12">
                      <label className="form-label fw-bold small">Nombre del Producto</label>
                      <input name="nombre" className="form-control" onChange={handleChange} required />
                    </div>
                    <div className="col-md-6">
                      <label className="form-label fw-bold small">Precio</label>
                      <input name="precio" type="number" step="0.01" className="form-control" onChange={handleChange} required />
                    </div>
                    <div className="col-md-6">
                      <label className="form-label fw-bold small">Stock Inicial</label>
                      <input name="stock" type="number" className="form-control" onChange={handleChange} required />
                    </div>
                    <div className="col-12">
                      <label className="form-label fw-bold small">Descripción</label>
                      <textarea name="descripcion" className="form-control" rows="2" onChange={handleChange}></textarea>
                    </div>
                    <div className="col-12">
                      <label className="form-label fw-bold small">Imagen</label>
                      <input type="file" accept="image/*" className="form-control" onChange={handleFileChange} />
                    </div>
                  </div>
                </div>
                <div className="modal-footer border-0 p-4">
                  <button type="button" className="btn btn-light fw-bold" onClick={() => setShowModal(false)}>Cancelar</button>
                  <button type="submit" className="btn btn-primary fw-bold px-4">Guardar Producto</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
